  "inlineSchema": "datasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"./generated/client\"\n}\n\nenum Role {\n  ADMIN\n  STUDENT\n}\n\nenum CourseStatus {\n  DRAFT\n  PUBLISHED\n}\n\nenum TransactionStatus {\n  PENDING\n  PAID\n  FAILED\n  EXPIRED\n}\n\nenum EnrollmentStatus {\n  ACTIVE\n  COMPLETED\n}\n\nmodel User {\n  id             String           @id @default(uuid())\n  email          String           @unique\n  password       String?\n  name           String\n  avatarUrl      String?\n  role           Role             @default(STUDENT)\n  createdAt      DateTime         @default(now())\n  updatedAt      DateTime         @updatedAt\n  enrollments    Enrollment[]\n  transactions   Transaction[]\n  lessonProgress LessonProgress[]\n  reviews        CourseReview[]\n  quizAttempts   QuizAttempt[]    @relation(\"UserQuizAttempts\")\n\n  @@map(\"users\")\n}\n\nmodel Course {\n  id              String         @id @default(cuid())\n  title           String\n  slug            String         @unique\n  description     String?        @db.Text\n  thumbnailUrl    String?\n  originalPrice   Int\n  discountedPrice Int?\n  duration        Int            @default(0) // total jam\n  status          CourseStatus   @default(DRAFT)\n  createdAt       DateTime       @default(now())\n  updatedAt       DateTime       @updatedAt\n  deletedAt       DateTime? // soft delete\n  modules         Module[]\n  enrollments     Enrollment[]\n  transactions    Transaction[]\n  reviews         CourseReview[]\n\n  @@index([status, deletedAt])\n  @@map(\"courses\")\n}\n\nmodel Module {\n  id        String   @id @default(cuid())\n  courseId  String\n  title     String\n  sortOrder Int      @default(0)\n  createdAt DateTime @default(now())\n  course    Course   @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  lessons   Lesson[]\n  quiz      Quiz?\n\n  @@index([courseId])\n  @@index([courseId, sortOrder])\n  @@map(\"modules\")\n}\n\nmodel Lesson {\n  id        String           @id @default(cuid())\n  moduleId  String\n  title     String\n  content   String?          @db.Text\n  videoUrl  String?\n  duration  Int              @default(0) // menit\n  sortOrder Int              @default(0)\n  createdAt DateTime         @default(now())\n  module    Module           @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  progress  LessonProgress[]\n\n  @@index([moduleId])\n  @@index([moduleId, sortOrder])\n  @@map(\"lessons\")\n}\n\nmodel Enrollment {\n  id             String           @id @default(cuid())\n  userId         String\n  courseId       String\n  enrolledAt     DateTime         @default(now())\n  status         EnrollmentStatus @default(ACTIVE)\n  certificateUrl String?\n  user           User             @relation(fields: [userId], references: [id])\n  course         Course           @relation(fields: [courseId], references: [id])\n\n  @@unique([userId, courseId])\n  @@index([userId, status])\n  @@index([courseId])\n  @@map(\"enrollments\")\n}\n\nmodel Transaction {\n  id              String            @id @default(cuid())\n  userId          String\n  courseId        String\n  amount          Int\n  status          TransactionStatus @default(PENDING)\n  paymentMethod   String?\n  paymentChannel  String?\n  mayarInvoiceId  String?           @unique\n  mayarInvoiceUrl String?\n  couponId        String?\n  discountAmount  Int?\n  paidAt          DateTime?\n  expiredAt       DateTime?\n  createdAt       DateTime          @default(now())\n  updatedAt       DateTime          @updatedAt\n  user            User              @relation(fields: [userId], references: [id])\n  course          Course            @relation(fields: [courseId], references: [id])\n  coupon          Coupon?           @relation(fields: [couponId], references: [id])\n  webhookLogs     WebhookLog[]\n\n  @@index([userId])\n  @@index([userId, status])\n  @@index([status])\n  @@index([createdAt])\n  @@map(\"transactions\")\n}\n\nmodel WebhookLog {\n  id            String       @id @default(cuid())\n  transactionId String?\n  event         String\n  payload       Json\n  httpStatus    Int          @default(200)\n  receivedAt    DateTime     @default(now())\n  transaction   Transaction? @relation(fields: [transactionId], references: [id])\n\n  @@index([transactionId])\n  @@index([receivedAt])\n  @@map(\"webhook_logs\")\n}\n\nmodel LessonProgress {\n  id          String    @id @default(cuid())\n  userId      String\n  lessonId    String\n  completed   Boolean   @default(false)\n  completedAt DateTime?\n  createdAt   DateTime  @default(now())\n  user        User      @relation(fields: [userId], references: [id])\n  lesson      Lesson    @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, lessonId])\n  @@index([userId, completed])\n  @@index([lessonId])\n  @@map(\"lesson_progress\")\n}\n\nmodel CourseReview {\n  id        String   @id @default(cuid())\n  userId    String\n  courseId  String\n  rating    Int // 1 to 5 stars\n  comment   String?  @db.Text\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  course    Course   @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, courseId]) // One review per user per course\n  @@index([courseId])\n  @@map(\"course_reviews\")\n}\n\nmodel Coupon {\n  id            String        @id @default(cuid())\n  code          String        @unique\n  discountType  String\n  discountValue Int\n  maxUses       Int?\n  usedCount     Int           @default(0)\n  minPurchase   Int?\n  validFrom     DateTime      @default(now())\n  validUntil    DateTime?\n  isActive      Boolean       @default(true)\n  courseId      String?\n  createdAt     DateTime      @default(now())\n  transactions  Transaction[]\n\n  @@index([code])\n  @@map(\"coupons\")\n}\n\nmodel Quiz {\n  id        String     @id @default(cuid())\n  moduleId  String     @unique\n  title     String\n  module    Module     @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  questions Question[]\n\n  @@index([moduleId])\n  @@map(\"quizzes\")\n}\n\nmodel Question {\n  id           String @id @default(cuid())\n  quizId       String\n  questionText String @db.Text\n  options      Json\n  correctIndex Int\n  sortOrder    Int    @default(0)\n  quiz         Quiz   @relation(fields: [quizId], references: [id], onDelete: Cascade)\n\n  @@index([quizId])\n  @@map(\"questions\")\n}\n\nmodel QuizAttempt {\n  id        String   @id @default(cuid())\n  userId    String\n  quizId    String\n  score     Int\n  totalQ    Int\n  answers   Json\n  createdAt DateTime @default(now())\n  user      User     @relation(\"UserQuizAttempts\", fields: [userId], references: [id])\n\n  @@index([userId, quizId])\n  @@map(\"quiz_attempts\")\n}\n",
